// TenancyServiceHandler is an implementation of the redmatrix.tenancy.v1.TenancyService service.
type TenancyServiceHandler interface {
	// CreateProject 创建项目（SA only）。name 在租户内唯一。
	CreateProject(context.Context, *connect.Request[v1.CreateProjectRequest]) (*connect.Response[v1.CreateProjectResponse], error)
	// ListProjects 列项目（SA / TA 全部；PA 限自己加入的——PA 过滤待 PR-T3
	// ProjectMember 落地后实现）。
	ListProjects(context.Context, *connect.Request[v1.ListProjectsRequest]) (*connect.Response[v1.ListProjectsResponse], error)
	// GetProject 取单个项目详情。
	GetProject(context.Context, *connect.Request[v1.GetProjectRequest]) (*connect.Response[v1.GetProjectResponse], error)
	// ArchiveProject 归档（幂等）。归档项目不可变（仅 unarchive / delete / read）。
	ArchiveProject(context.Context, *connect.Request[v1.ArchiveProjectRequest]) (*connect.Response[v1.ArchiveProjectResponse], error)
	// UnarchiveProject 取消归档（幂等）。
	UnarchiveProject(context.Context, *connect.Request[v1.UnarchiveProjectRequest]) (*connect.Response[v1.UnarchiveProjectResponse], error)
	// DeleteProject 软删（MVP 不级联资产 / 任务，由 LLD 11 §4.4 后续 PR 接）。
	DeleteProject(context.Context, *connect.Request[v1.DeleteProjectRequest]) (*connect.Response[v1.DeleteProjectResponse], error)
	// AddProjectMember 加成员（SA only）。被加用户必须 PROJECT_ADMIN 且 tenant 与项目一致。
	AddProjectMember(context.Context, *connect.Request[v1.AddProjectMemberRequest]) (*connect.Response[v1.AddProjectMemberResponse], error)
	// RemoveProjectMember 移除成员（SA only）。
	RemoveProjectMember(context.Context, *connect.Request[v1.RemoveProjectMemberRequest]) (*connect.Response[v1.RemoveProjectMemberResponse], error)
	// ListProjectMembers 列项目成员。SA + 该项目的 PA 可读。
	ListProjectMembers(context.Context, *connect.Request[v1.ListProjectMembersRequest]) (*connect.Response[v1.ListProjectMembersResponse], error)
	// CreateNode 手动注册节点（SA only）。
	CreateNode(context.Context, *connect.Request[v1.CreateNodeRequest]) (*connect.Response[v1.CreateNodeResponse], error)
	// ListNodes 列租户内节点。SA + TA 可读。
	ListNodes(context.Context, *connect.Request[v1.ListNodesRequest]) (*connect.Response[v1.ListNodesResponse], error)
	// GetNode 取单个节点。SA + TA 可读。
	GetNode(context.Context, *connect.Request[v1.GetNodeRequest]) (*connect.Response[v1.GetNodeResponse], error)
	// EnableNode 状态置 pending（SA only）。
	EnableNode(context.Context, *connect.Request[v1.EnableNodeRequest]) (*connect.Response[v1.EnableNodeResponse], error)
	// DisableNode 状态置 disabled（SA only）。
	DisableNode(context.Context, *connect.Request[v1.DisableNodeRequest]) (*connect.Response[v1.DisableNodeResponse], error)
	// DeleteNode 软删（SA only）。
	DeleteNode(context.Context, *connect.Request[v1.DeleteNodeRequest]) (*connect.Response[v1.DeleteNodeResponse], error)
	// SetProjectAllowedNodes 全量替换项目白名单（SA / 该项目 PA）。
	// 空 node_ids = 恢复 ALL 默认（所有节点可用）。
	SetProjectAllowedNodes(context.Context, *connect.Request[v1.SetProjectAllowedNodesRequest]) (*connect.Response[v1.SetProjectAllowedNodesResponse], error)
	// GetProjectAllowedNodes 取项目白名单。
	// 返 all_nodes=true 表示 ALL 默认；false 时 node_ids 是显式列表。
	GetProjectAllowedNodes(context.Context, *connect.Request[v1.GetProjectAllowedNodesRequest]) (*connect.Response[v1.GetProjectAllowedNodesResponse], error)
	// CreateRegistrationToken 生成一次性节点注册令牌（SA only）。
	// 返 plaintext 仅一次性显示。
	CreateRegistrationToken(context.Context, *connect.Request[v1.CreateRegistrationTokenRequest]) (*connect.Response[v1.CreateRegistrationTokenResponse], error)
	// ListRegistrationTokens 列租户全部令牌（SA + TA）。
	ListRegistrationTokens(context.Context, *connect.Request[v1.ListRegistrationTokensRequest]) (*connect.Response[v1.ListRegistrationTokensResponse], error)
	// RevokeRegistrationToken 撤销令牌（SA only）。
	RevokeRegistrationToken(context.Context, *connect.Request[v1.RevokeRegistrationTokenRequest]) (*connect.Response[v1.RevokeRegistrationTokenResponse], error)
	// RedeemRegistrationToken 真节点首次接入（公开 RPC；plaintext 自身即认证）。
	// 兑换 → 创建 Node 行（status=pending）+ 单次性消费 token。
	RedeemRegistrationToken(context.Context, *connect.Request[v1.RedeemRegistrationTokenRequest]) (*connect.Response[v1.RedeemRegistrationTokenResponse], error)
}

